### Disable PayloadCMS Plugin while Maintaining Schema (TypeScript)

Source: https://github.com/payloadcms/payload/blob/main/tools/claude-plugin/skills/payload/reference/PLUGIN-DEVELOPMENT.md

This pattern demonstrates how to design a PayloadCMS plugin that allows users to disable its functional aspects (endpoints, hooks, components) at runtime, while still ensuring its database schema changes (collections, fields) are always applied for consistency. It introduces a `disabled` option in the plugin configuration to control activation.

```typescript
import type { Config, Plugin } from 'payload'

interface PluginConfig {
  disabled?: boolean
  collections?: string[]
}

export const myPlugin =
  (options: PluginConfig): Plugin =>
  (config: Config): Config => {
    // Always add collections/fields for database schema consistency
    if (!config.collections) {
      config.collections = []
    }

    config.collections.push({
      slug: 'plugin-collection',
      fields: [{ name: 'title', type: 'text' }],
    })

    // Add fields to specified collections
    if (options.collections) {
      for (const collectionSlug of options.collections) {
        const collection = config.collections.find((c) => c.slug === collectionSlug)
        if (collection) {
          collection.fields.push({
            name: 'addedByPlugin',
            type: 'text',
          })
        }
      }
    }

    // If disabled, return early but keep schema changes
    if (options.disabled) {
      return config
    }

    // Add endpoints, hooks, components only when enabled
    config.endpoints = [
      ...(config.endpoints ?? []),
      {
        path: '/my-endpoint',
        method: 'get',
        handler: async () => Response.json({ message: 'Hello' }),
      },
    ]

    return config
  }
```

